+        // Format invariants:
+        assert!(h.starts_with("$6$saltstring$"));
+        // 86 crypt-base64 chars after the salt $ separator.
+        assert_eq!(h.len(), "$6$saltstring$".len() + 86);
+        // No rounds= prefix when defaulted.
+        assert!(!h.contains("rounds="));
+    }
